<template>
  <section>
    <loader :is-visible="isLoading"></loader>
    <tg-list ref="tgList" :listType="['List', 'Card']" :IsShowAction="false" :showCheckBox="true" ModuleName="PROJECT"
      SubModuleCode="Task" IdentityColumn="task_id" :HeaderText="$t('Manage Tasks')" :ListData="TaskData"
      :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords"
      :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData"
      :SortExp="SortExp" :SortBy="SortBy" :LegendArray="LegendArray" :NorecordfoundText="$t('NoRecordfound')"
      v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
      v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
      v-on:SortdataButtonClick="sortdata" :Key="Key" :routeInfo="$router">
      <template v-slot:slotdata="{ data }">
        <template v-if="data.column.COLUMN_NAME == 'status_name'">
          <listing-status :isfor="'TASKLISTING'" ref="updatestatus" v-bind:dataid="data.row.task_id"
            data-controller="Task" v-bind:statuslist="StatusList" v-bind:item="data"
            v-bind:parentid="data.row.ParentTaskId" data-action="index" v-bind:dataselected="data.row.status_name"
            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
          </listing-status>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'task_name'">
                    <span > {{ data.row.task_number }} {{ TruncateStr(data.row.task_name,15) }}</span>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'Current_Progress'">
          <div class="Task">
            <div>
              <progress id="progress-bar-1" :value="data.row.Current_Progress" max="100"></progress>
              <div class="vue-simple-progress-text" id="progress-text"
                style="color: rgb(34, 34, 34); font-size: 12px; text-align: center; padding-top: 3px;">
                {{ data.row.Current_Progress }} % {{ $t('Completed') }}</div>
            </div>
          </div>
          <a v-if="(data.row.IS_INCLUDE_IN_TASK > 0 || UserType != 'CL') && data.row.PROJECTTASKPROGRESS != 'TIMER_BASED'"
            class="text-success align-top mt-0 d-inline-block text-right" data-toggle-tooltip="tooltip"
            data-original-title="Manage Progress" @click="EditTaskProgress(data.row, this)">
            <i class="fa fa-pencil"></i>
          </a>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'TEAMMEMBER'">         
          <a href="javascript:;" v-if="data.row.level == 0" 
            v-bind:data-content="GetCommaSepratedTeams(data.row.TEAMMEMBER)"><span><i
                class="fa fa-user-o text-dark"></i><span class="noti-circle noti-green">{{
                  GetCommaSepratedTeams(data.row.TEAMMEMBER, 'length') }}</span></span></a>
          <a href="javascript:;" v-if="data.row.level > 0" title="View" data-toggle="popovers" popover-title="Team"
            v-bind:data-content="GetCommaSepratedTeams(data.row.Team, 'team')"><span><i
                class="fa fa-user-o text-dark"></i><span class="noti-circle noti-green">{{ (data.row.Team ==
                  null ? 0 : data.row.Team.length) }}</span></span></a>
        </template>
        <template v-if="data.column.COLUMN_NAME == 'planned_start_date'">
           {{ data.row.planned_start_date == null ? '--' : $d(data.row.planned_start_date)
                    }}
        </template>
        <template v-if="data.column.COLUMN_NAME == 'planned_end_date'">
         {{ data.row.planned_end_date == null ? '--' : $d(data.row.planned_end_date) }}
        </template>
        <template v-if="data.column.COLUMN_NAME == 'HOURSPEND'">
          {{ secondsToHours(data.row.HOURSPEND) }}
        </template>
        <template v-if="data.column.COLUMN_NAME == 'estimated_hours'">
          {{ secondsToHours(data.row.ESTIMATED_HOURS) }}
        </template>
        <template v-if="data.column.COLUMN_NAME == 'allowtimer'">
          <div class="text-center"
            v-if="data.row.IS_INCLUDE_IN_TASK > 0 && data.row.allowtimer > 0 && (data.row.status_code != 'STATUS_DONE' && data.row.status_code != 'PCAN' && data.row.status_code != 'PCLSD' && data.row.status_code != 'INACT')">
            <div v-if="data.row.isRunning > 0" class="single-action">
              <a class="StartStopTimer" type="stopTimer" title="Stop Timer"
                v-on:click="StartStopTimer('stopTimer', data.row.task_id, data.row.isRunning, data.row.IS_BILLABLE)"
                id="StopTimer" href="javascript:;"><em class="fa fa-stop-circle text-info action-icon"></em></a>
            </div>
            <div v-else class="single-action">
              <a class="StartStopTimer" type="startTimer"
                v-on:click="StartStopTimer('startTimer', data.row.task_id, data.row.isRunning, data.row.IS_BILLABLE)"
                title="Start Timer" id="StartTimer" href="javascript:;">
                <em class="fa fa-play-circle text-info action-icon"></em>
              </a>
            </div>
          </div>
          <div v-else class="single-action text-center">
            <a class="disabled">
              <em class="fa fa-play-circle text-secondary action-icon"></em>
            </a>
          </div>
        </template>
      </template>

      <template v-slot:customcard="{ data }">
        <div class="card-box expense-card pb-2">
          <div class="expense-card-header">
            <div class="custom-control custom-checkbox custom-control-inline">
              <input type="checkbox" class="chkItems custom-control-input" v-on:change="ForCheckBoxClear($event)"
                :value="data.row.task_id" :id="'chk' + data.row.task_id" style="display: none;">
              <label class="custom-control-label" type="checkbox" :for="'chk' + data.row.task_id"></label>
              <a title="" class="text-truncate expense-title" :value="data.row.TaskId" data-toggle-tooltip="tooltip"
                style="cursor: default;" data-original-title="text">{{ $t('TaskName') }} - <span class="blue-time">{{ data.row.task_number }} {{TruncateStr(data.row.task_name,15) }}</span></a>
            </div>
          </div>

          <div class="card-detail-main">
            <div class="card-detail mt-2">
              <em class="fa fa-exclamation-triangle"></em>
              <span class="float-left w-auto mr-1">{{ $t('Status') }} -</span>
              <span class="text-center single-action float-left w-auto">
                <listing-status :isfor="'TASKLISTING'" ref="updatestatus" v-bind:dataid="data.row.task_id"
                  data-controller="Task" v-bind:statuslist="StatusList" v-bind:item="data"
                  v-bind:parentid="data.row.ParentTaskId" data-action="index" v-bind:dataselected="data.row.status_name"
                  v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
                </listing-status>
              </span>
              <span class="text-center single-action float-left w-auto"
                v-if="((UserType == 'NU' || UserType == 'PM') && data.row.user_type_id == 3)">
                <a class="inactive-disabled">
                  <span class="btn text-center w-100"
                    v-bind:style="{ 'background-color': data.row.status_bg_color, 'color': data.row.status_color }"
                    style="cursor: default;">{{ data.row.project_status }}</span>
                </a>
              </span>
            </div>
            <div class="card-detail"><em class="fa fa-suitcase"></em> <span>{{ $t('ProjectName') }} -
                {{ data.row.PROJECT_NAME }}</span></div>
            <div class="card-detail"><em class="fa fa-calendar"></em> <span>{{ $t('TimeTracked') }} -
                {{ secondsToHours(data.row.HOURSPEND) }}</span></div>
            <div class="card-detail"><em class="fa fa-calendar"></em> <span>{{ $t('TotalTime') }} -
                {{ secondsToHours(data.row.ESTIMATED_HOURS) }}</span></div>
            <div class="card-detail" v-if="(data.row.STARTDATE != null && data.row.ENDDATE != null)"><em
                class="fa fa-calendar-o" aria-hidden="true"></em>
              <span> {{ data.row.planned_start_date == null ? '--' : $d(data.row.planned_start_date)
                    }} -
                 {{ data.row.planned_end_date == null ? '--' : $d(data.row.planned_end_date) }}</span>
            </div>
            <a :id="'a' + data.row.task_id" @click="ShowMore('showdiv' + data.row.task_id)" href="javascript:;"
              :class="{ 'read-more-content': true, 'hide': ShowMoreFalse == true }">{{
                $t('More') }}</a>
            <div :class="{ 'read-more-content': true, 'hide': ShowMoreFalse == false }"
              :id="'showdiv' + data.row.task_id">
              <div class="spac-eq border-top text-center">
                <div class="card-action mt-2 mb-0 w-100 text-center">
                  <a href="javascript:;" v-if="data.row.level == 0" title="View" data-toggle="popovers"
                    popover-title="Team" v-bind:data-content="GetCommaSepratedTeams(data.row.TEAMMEMBER)"><span><em
                        class="fa fa-user-o text-dark"></em><span class="noti-circle noti-green">{{
                          GetCommaSepratedTeams(data.row.TEAMMEMBER, 'length') }}</span></span></a>
                  <a href="javascript:;" v-if="data.row.level > 0" title="View" data-toggle="popovers"
                    popover-title="Team" v-bind:data-content="GetCommaSepratedTeams(data.row.Team, 'team')"><span><em
                        class="fa fa-user-o text-dark"></em><span class="noti-circle noti-green">{{ (data.row.Team ==
                          null ? 0 :
                          data.row.Team.length) }}</span></span></a>
                  <div style="display: -webkit-inline-box;"
                    v-if="data.row.allowtimer > 0 && (data.row.status_code != 'STATUS_DONE' && data.row.status_code != 'PCAN' && data.row.status_code != 'PCLSD' && data.row.status_code != 'INACT')">
                    <div v-if="data.row.isRunning > 0" class="single-action">
                      <a class="StartStopTimer" type="stopTimer" title="Stop Timer"
                        v-on:click="StartStopTimer('stopTimer', data.row.task_id, data.row.isRunning, data.row.IS_BILLABLE)"
                        id="StopTimer" href="javascript:;"><em class="fa fa-stop-circle text-info action-icon"></em></a>
                    </div>
                    <div v-else class="single-action">
                      <a class="StartStopTimer" type="startTimer"
                        v-on:click="StartStopTimer('startTimer', data.row.task_id, data.row.isRunning, data.row.IS_BILLABLE)"
                        title="Start Timer" id="StartTimer" href="javascript:;">
                        <em class="fa fa-play-circle text-info action-icon"></em>
                      </a>
                    </div>
                  </div>
                  <a class="disabled" v-else>
                    <em class="fa fa-play-circle text-secondary action-icon"></em>
                  </a>
                </div>
              </div>
              <div class="spac-eq border-top text-center">
                <div class="time">
                  <progress id="progress-bar-1" :value="data.row.Current_Progress" max="100"></progress>
                  <div class="vue-simple-progress-text" id="progress-text"
                    style="color: rgb(34, 34, 34); font-size: 12px; text-align: center; padding-top: 3px;">
                    {{ data.row.Current_Progress }} % {{ $t('Completed') }}</div>
                </div>
              </div>
              <div class="spac-eq border-top text-center pt-2">
                <div class="Task">
                  <div v-bind:class="'c100 small green p' + parseInt(data.row.current_progress, 10)">
                    <span>{{ data.row.current_progress }}%</span>
                    <div class="slice">
                      <div v-bind:class="{ 'bar': data.row.current_progress > 0 }"></div>
                      <div class="fill"></div>
                    </div>
                  </div>
                  <span class="t-title">{{ $t('Completed') }}</span>
                </div>
              </div>
              <a id="cardMoreDataLess" @click="ShowLess('showdiv' + data.row.task_id)" href="javascript:;"
                :class="{ 'read-more-hide': true, '': ShowMoreFalse == true }">{{ $t('Less') }}</a>
            </div>
            <div class="verticle-action " v-if="data.row.PROJECTTASKPROGRESS != 'TIMER_BASED'">
              <i class="fa fa-ellipsis-v action_icon_cv" aria-hidden="true"></i>
              <span class="action-list-box small">
                <span class="list-actions fsm-list" id="action-list">
                  <div class="float-left">
                    <div class="float-left">
                      <a v-if="data.row.PROJECTTASKPROGRESS != 'TIMER_BASED'" title="Manage Progress"
                        data-placement="left" class="update actions-onclick border-bottom-0" checkPrivilege="yes"
                        v-on:click="EditTaskProgress(data.row, this)" href="javascript:;" style="cursor:pointer;">
                        <em class="fa fa-pencil action-icon"></em>
                        <span class="text">{{ $t('Manage') }} {{ $t('Progress') }}</span>
                      </a>
                    </div>
                  </div>
                  <em class="fa fa-times close close-action_cv" aria-hidden="true"></em>
                </span>
              </span>
            </div>
          </div>
        </div>
      </template>
    </tg-list>
    <TaskProgress v-if="ShowTaskProgress" :TaskItemData="TaskItemData" :Type="IsTaskType" @GetTaskList="GetTaskList" @CloseModal="CloseModal"></TaskProgress>
  </section>
</template>
<script>
import DataService from '../../../services/DataService';
import TaskProgress from '../../../components/Modal/modaltaskprogress.vue'
import Schema from './Schema'
export default {
  components: { TaskProgress },
  data() {
    return {
      isLoading: false,
      ShowMoreFalse: false,
      SortExp: '',
      SortBy: '',
      LegendArray: [],
      widgets: [
        {
          icon: "fa fa-folder",
          value: "",
          name: "Total Task",
          class: "one_wid",
          onClick: this.widgetClick
        },
        {
          icon: "fa fa-folder-open",
          value: "",
          name: "In Progress",
          class: "two_wid",
          onClick: this.widgetClick
        },
        {
          icon: "fa fa-calendar-check-o",
          value: "",
          name: "Pending",
          class: "three_wid",
          onClick: this.widgetClick
        },
        {
          icon: "fa fa-calendar-check-o",
          value: "",
          name: "Completed",
          class: "four_wid",
          onClick: this.widgetClick
        },
        {
          icon: "fa fa-list-ul",
          value: "",
          name: "Closed",
          class: "five_wid",
          onClick: this.widgetClick
        }
      ],
      searchCondition: '',
      TotalRecords: 0,
      PageNumber: 1,
      PageSize: 10,
      Status: '',
      IsTaskType:'Task',
      Headers: [
        {
          "COLUMN_NAME": "task_name",
          "DATA_TYPE": "string",
          "SORTABLE": true,
          "VISIBLE": true,
          "DISPLAY_NAME": "Key/Task Name",
          "DISPLAY_ORDER": 1,
          settings : {
              isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "PROJECT_NAME",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Project",
          "DISPLAY_ORDER": 2
        },
        {
          "COLUMN_NAME": "TEAMMEMBER",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Team Members",
          "DISPLAY_ORDER": 3,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "planned_start_date",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Start Date",
          "DISPLAY_ORDER": 4,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "planned_end_date",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "End Date",
          "DISPLAY_ORDER": 5,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "HOURSPEND",
          "DATA_TYPE": "boolean",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Time Tracked",
          "DISPLAY_ORDER": 6,
          settings: {
            isInSlot: true
          }
        },

        {
          "COLUMN_NAME": "estimated_hours",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Total Time",
          "DISPLAY_ORDER": 7,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "Current_Progress",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "% Completed",
          "DISPLAY_ORDER": 8,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "status_name",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Status",
          "DISPLAY_ORDER": 8,
          settings: {
            isInSlot: true
          }
        },
        {
          "COLUMN_NAME": "allowtimer",
          "DATA_TYPE": "string",
          "SORTABLE": false,
          "VISIBLE": true,
          "DISPLAY_NAME": "Start Time",
          "DISPLAY_ORDER": 8,
          settings: {
            isInSlot: true
          }
        }],
      
      TaskData: [],
      listheaderbuttons: Schema.buttons,
      leftSearchFields: Schema.leftsearchSchema,
      secondsPerMinute: 60,
      minutesPerHour: 60,
      ActiveRecords: null,
      InActiveRecords: null,
      CancelledRecords: null,
      ClosedRecords: null,
      PendingRecords: null,
      PlanningRecords: null,
      InProgressRecords: null,
      CompletedRecords: null,
      TotalTaskRecords: null,
      ParentTaskData: [],
      CompanyId: null,
      UserType: null,
      inprogressData: [],
      activeData: [],
      pendingData: [],
      comData: [],
      inactiveData: [],
      cancelData: [],
      closeData: [],
      StatusList: [],
      ShowTaskProgress: false,
      TaskItemData: null
    }
  },
  created: function () {
    var ths = this;
    ths.FetchData();
    ths.StatusDropdown();
    ths.CompanyId = ths.GetUserInfo.CompanyId;
    ths.UserType = ths.GetUserInfo.UserType;
  },
  methods: {
    ShowMore(ths) {
      $('#' + ths).show();
      $('#a' + ths.split('v')[1]).hide();
    },
    ShowLess(ths) {
      $('#' + ths).hide();
      $('#a' + ths.split('v')[1]).show();
    },
    EditTaskProgress: function (item, ctrl) {
      var vm = this;
      vm.TaskItemData = item;
      vm.ShowTaskProgress = true;
    },
    GetCommaSepratedTeams: function (team, type) {
      var str = "";
      if (team != null && team.length == 0) {
        str = 0;
      }
      if (team != null && team.length > 0) {
        if (type == "length") {
          team = String(team).split(',');
          return team.length;
        }
        else if (type == "team") {
          $.each(team, function (index, item) {
            if (str.length > 0) {
              str += "<br/>";
            }
            str += (index + 1) + ". " + item.UserName;
          });
        }
        else {
          team = String(team).split(',');
          $.each(team, function (index, item) {
            if (str.length > 0) {
              str += "<br/>";
            }
            if (type == "tag") {
              str += '<a type="button" class="btn listing-tag bg-grey px-3" style="cursor:none;"><span class="tag-name team-name list">' + item.TagName + '</span></a>';
            }
            else {
              str += (index + 1) + ". " + item;
            }
          });
        }
      }
      return str;
    },
    StatusDropdown: function () {
      var vm = this;
      var url = `langCode=en&companyId=${vm.CompanyId}&statusType=Project&hasGlobal=true`
      DataService.StatusListing(url).then((response) => {
        if (response.data != null && response.data != "") {
          vm.StatusList = response.data.result.data;
        }
      });
    },
    secondsToHours(seconds) {
            if (isNaN(seconds) || seconds < 0) return "0 Hours 0 Min";
            let hours = Math.floor(seconds / 3600);
            let minutes = Math.floor((seconds % 3600) / 60);
            return `${hours} Hours ${minutes} Min`;
        },
    convertSecondsToHHMMSSNew: function (intSecondsToConvert) {
      var hours = this.convertHours(intSecondsToConvert);
      var minutes = this.getRemainingMinutes(intSecondsToConvert);
      minutes = minutes == 60 ? "00" : minutes;
      var seconds = this.getRemainingSeconds(intSecondsToConvert);
      if (hours < 10) hours = "0" + hours;
      if (minutes < 10) minutes = "0" + minutes;
      if (seconds < 10) seconds = "0" + seconds;
      return hours + ":" + minutes + " Hrs";
    },
    convertMinutes: function (intSeconds) {
      return Math.floor(intSeconds / this.secondsPerMinute)
    },
    convertHours: function (intSeconds) {
      var minutes = this.convertMinutes(intSeconds);
      var hours = Math.floor(minutes / this.minutesPerHour);
      return hours
    },
    getRemainingMinutes: function (intSeconds) {
      var intTotalMinutes = this.convertMinutes(intSeconds);
      return intTotalMinutes % this.minutesPerHour
    },
    getRemainingSeconds: function (intTotalSeconds) {
      return intTotalSeconds % this.secondsPerMinute
    },
    widgetClick: function (code) {
      var vueObj = this;
      if (code.name == 'Total Task') {
        vueObj.Status = "";
      }
      else if (code.name == 'In Progress') {
        vueObj.Status = "Inprogress";
      }
      else if (code.name == 'Pending') {
        vueObj.Status = "pending";
      }
      else if (code.name == 'Completed') {
        vueObj.Status = "Completed";
      }
      else if (code.name == 'Closed') {
        vueObj.Status = "Closed";
      }
      vueObj.FetchData();
    },
    sortdata: function (s) {
      var SortDir = "sort tb_headerSortDown";
      this.SortBy = s;
      if (s === this.SortBy) {
        if (this.SortExp == "") {
          this.SortExp = "ASC";
          SortDir = "sort tb_headerSortDown";
        }
        else if (this.SortExp == "ASC") {
          this.SortExp = "DESC";
          SortDir = "sort tb_headerSortUp";
        }
        else {
          this.SortExp = "ASC";
          SortDir = "sort tb_headerSortDown";
        }
      }
      this.FetchData();
      $("#" + s + '  span:first-child').attr("class", SortDir);
    },
    commonHeaderButtonClick: function (event) {
      switch (event.callbackfunction) {
        case "commonDeleteData":
          this.commonDeleteData();
          break;
      }
    },
    pagerMethod: function (value) {
      this.PageSize = value.PageSize;
      this.PageNumber = value.PageNumber;
      this.FetchData();
    },
    leftCommonSearch: function (value) {
      this.PageNumber = value.PageNumber;
      this.isPaged = 1;
      if (typeof value.searchCondition != 'undefined') {
        if (value.searchConditionJson != '') {
          this.searchCondition = value.searchConditionJson;
        }
      }
      else {
        this.searchCondition = "";
      }
      this.FetchData();
    },
    actionButtonClick: function (callbackfunction, item) { },
    renderActions: function (row) { },
    FetchData:async function () {  
      var ths = this;
      ths.isLoading = true; 
            var url='controller=Task&action=Index'
            await DataService.CheckPrivilege(url).then(async function (response) {                
         if (response.data) {
          if (ths.isBlank(ths.searchCondition)) {
        var url = `sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&totalRecords=&status=${ths.Status}`;
      } else {
        var url = `sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&totalRecords=&status=${ths.Status}&${ths.searchCondition}`;
      }
      DataService.TaskListing(url).then((response) => {
        ths.isLoading = false;
        if (response.data.result.DATA.length > 0) {
          let taskData = response.data.result.DATA;
          ths.TotalRecords = response.data.result.DATA[0].TOTAL_RECORDS;
          ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
          ths.CurrentPage = ths.PageNumber;
          taskData.forEach((x) => {
            if(x.planned_start_date != null){
                x.planned_start_date= new Date(x.planned_start_date);
            }
            if(x.planned_end_date != null){
                x.planned_end_date= new Date(x.planned_end_date);
            } 
            x.child = {
              onExpandChild: ths.onExpandChild,
              isShowChild: false,
              isShowExpandButton: true,
              data: [],
              Header: []
            }
          });
          ths.TaskData = taskData
          if (response.data.result.DATA[0].TOTAL_RECORDS == 0) {
            ths.widgets[0].value = 0;
          }
          else {
            ths.widgets[0].value = response.data.result.DATA[0].TOTAL_RECORDS;
          }
          if (response.data.result.DATA[0].INPROGRESSRECORDS == 0) {
            ths.widgets[1].value = 0;
          }
          else {
            ths.widgets[1].value = response.data.result.DATA[0].INPROGRESSRECORDS;
          }
          if (response.data.result.DATA[0].PENDINGRECORDS == 0) {
            ths.widgets[2].value = 0;
          }
          else {
            ths.widgets[2].value = response.data.result.DATA[0].PENDINGRECORDS;
          }
          if (response.data.result.DATA[0].COMPLETEDRECORDS == 0) {
            ths.widgets[3].value = 0;
          }
          else {
            ths.widgets[3].value = response.data.result.DATA[0].COMPLETEDRECORDS;
          }
          if (response.data.result.DATA[0].CLOSEDRECORDS == 0) {
            ths.widgets[4].value = 0;
          }
          else {
            ths.widgets[4].value = response.data.result.DATA[0].CLOSEDRECORDS;
          }
        }
      });
               } else {
                ths.isLoading = false; 
                ths.ShowAlert(ths.$t('NotAuthorizedSection'), "failure", true, "Alert");
          } 
                });    



    

    },
    onExpandChild: async function (item) {
      var ths = this;
      var url = `ProjectId=${item.ProjectId}&TaskId=${item.task_id}&taskname=`;
      DataService.GetSubListing(url).then((response) => {
        debugger
        if (response.data.result.Data.length > 0) {        
          item.child.data = response.data.result.Data;
          item.child.data.forEach((x)=>{
              if(x.planned_start_date != null){
                  x.planned_start_date= new Date(x.planned_start_date);
              }
              if(x.planned_end_date != null){
                  x.planned_end_date= new Date(x.planned_end_date);
              } 
          })
          item.child.Header = ths.Headers
        }
        else {
          ths.noRecord = true;
          item.tasks = [];
          ths.TotalRecords = 0
        }
      })
    },
    commonDeleteData:async function (id) {
      var vm = this;
      vm.isLoading = true;
       var url='controller=Task&action=Delete'
                 await DataService.CheckPrivilege(url).then(async function (response) {                
         if (response.data) {
          var val = "";
      $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
        if (val.length > 0)
          val += ',';
        val += $(this).val();
      });
      if (val == "") {
        $('.chkItemsCard:checkbox:checked').not("[id^='chkAll']").each(function () {
          if (val.length > 0)
            val += ',';
          val += $(this).val();
        });
      }
      if (val.length > 0) {
        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Tasks")), function () {
          var postJSON = {
            ids: val
          };
          var objectPostString = JSON.stringify(postJSON);
          DataService.DeleteTask(objectPostString).then(function (response) {
            if (response.data.result == '100') {
              vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Project')]), "success", true, vm.$t("Alert"));
              vm.FetchData();
              vm.Key++;
            }
            else {
              vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Project')]), "failure", true, vm.$t("Alert"));
            }
          });
        });
      }
      else {
        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
      }
      vm.isLoading = false; 
               } else {
                vm.isLoading = false; 
                   vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
          } 
                });   

    
